const emoji = { 
  Positive: '🟢', 
  Negative: '🔴', 
  Neutral: '⚪', 
  Mixed: '🟡' 
};

const categoryEmoji = {
  'Stock': '📈',
  'Index': '📊',
  'Mutual Fund': '💼',
  'Commodity': '🥇',
  'FD': '🏦',
  'Crypto': '₿',
  'Economy': '🏛️'
};

const results = $json.data;
const date = new Date().toLocaleDateString('en-IN', { 
  day: 'numeric', month: 'short', year: 'numeric' 
});

// Helper to format one stock entry
function formatItem(r) {
  const sentimentMatch = r.analysis ? r.analysis.match(/SENTIMENT:\s*(\w+)/) : null;
  const summaryMatch = r.analysis ? r.analysis.match(/SUMMARY:\s*(.+?)(?:\n|KEY_EVENT|$)/s) : null;
  const keyEventMatch = r.analysis ? r.analysis.match(/KEY_EVENT:\s*(.+)/) : null;

  const sentiment = sentimentMatch ? sentimentMatch[1].trim() : 'Neutral';
  const summary = summaryMatch ? summaryMatch[1].trim() : 'No significant recent news.';
  const keyEvent = keyEventMatch ? keyEventMatch[1].trim() : 'None';

  const e = emoji[sentiment] || '⚪';
  let text = `${e} *${r.companyName}*\n${summary}\n`;
  if (keyEvent && keyEvent !== 'None') {
    text += `📌 _${keyEvent}_\n`;
  }
  return text;
}

// Split array into chunks of n
function chunkArray(arr, n) {
  const chunks = [];
  for (let i = 0; i < arr.length; i += n) {
    chunks.push(arr.slice(i, i + n));
  }
  return chunks;
}

// Group by category
const grouped = {};
for (const r of results) {
  const cat = r.category || 'Other';
  if (!grouped[cat]) grouped[cat] = [];
  grouped[cat].push(r);
}

const messages = [];

// Header
messages.push({
  message: `🗞 *Daily Investment Digest*\n📅 ${date}\n━━━━━━━━━━━━━━━━━━━━\nYour complete market overview 👇`
});

for (const [category, items] of Object.entries(grouped)) {
  const chunks = chunkArray(items, 8);

  chunks.forEach((chunk, index) => {
    const partLabel = chunks.length > 1 ? ` (Part ${index + 1}/${chunks.length})` : '';
    let msg = `${categoryEmoji[category] || '📌'} *${category.toUpperCase()}${partLabel}*\n`;
    msg += `━━━━━━━━━━━━━━━━━━━━\n\n`;

    for (const r of chunk) {
      msg += formatItem(r);
      msg += '\n';
    }

    messages.push({ message: msg });
  });
}

// Footer
messages.push({
  message: `━━━━━━━━━━━━━━━━━━━━\n_Powered by your n8n Stock Bot_ 🤖\n_Data: NewsAPI & OpenRouter_`
});

return messages.map(m => ({ json: m }));
